// ============================================================================
// LOAD FULL CONTEXT FROM SUPABASE - MILO FINAL
// ============================================================================
// Charge: project, task, brand_memory, project_memory, user_integrations
// ============================================================================

const userInput = $('Webhook Trigger').item.json.body || $('Webhook Trigger').item.json;
const projectId = userInput.project_id;
const taskId = userInput.task_id;

if (!projectId) {
  throw new Error('project_id is required');
}

// ─────────────────────────────────────────────────────────────────────────
// SUPABASE CLIENT (à configurer dans n8n credentials)
// ─────────────────────────────────────────────────────────────────────────
const SUPABASE_URL = $env.SUPABASE_URL || 'https://your-project.supabase.co';
const SUPABASE_ANON_KEY = $env.SUPABASE_ANON_KEY;

if (!SUPABASE_URL || !SUPABASE_ANON_KEY) {
  throw new Error('SUPABASE_URL and SUPABASE_ANON_KEY must be set in environment variables');
}

// Helper: Supabase request
async function supabaseRequest(endpoint, options = {}) {
  const response = await fetch(`${SUPABASE_URL}/rest/v1/${endpoint}`, {
    ...options,
    headers: {
      'apikey': SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
      'Content-Type': 'application/json',
      ...options.headers
    }
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Supabase error (${response.status}): ${errorText}`);
  }

  return await response.json();
}

// ─────────────────────────────────────────────────────────────────────────
// 1. LOAD PROJECT
// ─────────────────────────────────────────────────────────────────────────
const projects = await supabaseRequest(`projects?id=eq.${projectId}&select=*`);
const project = projects[0];

if (!project) {
  throw new Error(`Project ${projectId} not found`);
}

// ─────────────────────────────────────────────────────────────────────────
// 2. LOAD TASK (si fourni)
// ─────────────────────────────────────────────────────────────────────────
let task = null;
if (taskId) {
  const tasks = await supabaseRequest(`tasks?id=eq.${taskId}&select=*`);
  task = tasks[0];
}

// ─────────────────────────────────────────────────────────────────────────
// 3. LOAD PROJECT MEMORY (dernières 20 entrées)
// ─────────────────────────────────────────────────────────────────────────
const projectMemory = await supabaseRequest(
  `project_memory?project_id=eq.${projectId}&select=*&order=created_at.desc&limit=20`
);

// ─────────────────────────────────────────────────────────────────────────
// 4. LOAD BRAND IDENTITY (from project metadata)
// ─────────────────────────────────────────────────────────────────────────
const brandIdentity = project.metadata?.brand_identity || {
  brand_name: project.name,
  tone_of_voice: "Professional yet approachable",
  visual_style: "Modern, Clean",
  primary_colors: ["#FF6B6B", "#4ECDC4"],
  target_audience: "Marketing professionals"
};

// ─────────────────────────────────────────────────────────────────────────
// 5. EXTRACT STRATEGY FROM MEMORY (Luna's work)
// ─────────────────────────────────────────────────────────────────────────
const strategyMemory = projectMemory.find(m => 
  m.agent_id === 'luna' && m.action === 'STRATEGY_VALIDATED'
);

const strategy = strategyMemory ? {
  summary: strategyMemory.summary,
  key_findings: strategyMemory.key_findings || [],
  recommendations: strategyMemory.recommendations || []
} : {
  summary: "No strategy defined yet",
  key_findings: [],
  recommendations: []
};

// ─────────────────────────────────────────────────────────────────────────
// 6. RETURN FULL CONTEXT
// ─────────────────────────────────────────────────────────────────────────
return [{
  json: {
    project,
    task,
    brand_identity: brandIdentity,
    strategy,
    project_memory: projectMemory,
    user_input: userInput,
    session_id: userInput.session_id || `session_${Date.now()}`,
    timestamp: new Date().toISOString()
  }
}];

// ============================================================================
// CHECK TASK DEPENDENCIES - PHASE 0 SECURITY
// ============================================================================
// Uses: can_start_task() from migration 007
// ============================================================================

const context = $input.first().json;
const task = context.task;

// Skip if no task (chat-based request)
if (!task) {
  return [{ json: { ...context, dependencies_ok: true, skip_reason: 'no_task' } }];
}

// Skip if task already in_progress or done
if (task.status === 'in_progress' || task.status === 'done') {
  return [{ json: { ...context, dependencies_ok: true, skip_reason: 'task_already_started' } }];
}

// ─────────────────────────────────────────────────────────────────────────
// CALL can_start_task() SQL FUNCTION
// ─────────────────────────────────────────────────────────────────────────
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_ANON_KEY = $env.SUPABASE_ANON_KEY;

const response = await fetch(`${SUPABASE_URL}/rest/v1/rpc/can_start_task`, {
  method: 'POST',
  headers: {
    'apikey': SUPABASE_ANON_KEY,
    'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({ p_task_id: task.id })
});

if (!response.ok) {
  const errorText = await response.text();
  throw new Error(`Failed to check dependencies: ${errorText}`);
}

const result = await response.json();
const checkResult = Array.isArray(result) ? result[0] : result;

// ─────────────────────────────────────────────────────────────────────────
// IF DEPENDENCIES NOT MET → BLOCK & RETURN ERROR UI COMPONENT
// ─────────────────────────────────────────────────────────────────────────
if (!checkResult.ready) {
  // Get blocking tasks for UI
  const blockingResponse = await fetch(`${SUPABASE_URL}/rest/v1/rpc/get_blocking_tasks`, {
    method: 'POST',
    headers: {
      'apikey': SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({ p_task_id: task.id })
  });

  const blockingTasks = await blockingResponse.json();

  // Return error with UI component
  throw new Error(JSON.stringify({
    dependencies_not_met: true,
    error_message: checkResult.error_message,
    blocking_count: checkResult.blocking_count,
    missing_deliverables_count: checkResult.missing_deliverables_count,
    blocking_tasks: blockingTasks,
    ui_component: {
      type: 'DEPENDENCIES_BLOCKED',
      data: {
        error: checkResult.error_message,
        blocking_tasks: blockingTasks,
        resolution: 'Complete the blocking tasks before starting this one.'
      }
    }
  }));
}

// ─────────────────────────────────────────────────────────────────────────
// DEPENDENCIES OK → CONTINUE
// ─────────────────────────────────────────────────────────────────────────
return [{ json: { ...context, dependencies_ok: true } }];

// ============================================================================
// CHECK STATE FLAGS - PHASE 0 SECURITY
// ============================================================================
// Validates required state_flags before certain actions
// ============================================================================

const context = $input.first().json;
const project = context.project;
const task = context.task;
const userInput = context.user_input;

// Flags required for Milo's actions
const MILO_FLAG_RULES = {
  generate_creatives: {
    required_flags: ['tracking_ready'], // Need Sora to setup tracking first
    required_phase: ['Production', 'Execution'],
    message: 'Tracking must be set up before creating ads'
  },
  generate_video_batch: {
    required_flags: ['strategy_validated'], // Need Luna's strategy
    required_phase: ['Production', 'Execution'],
    message: 'Strategy must be validated before creating video content'
  }
};

// Determine action from user input
const action = userInput.action || 'generate_creatives';
const rule = MILO_FLAG_RULES[action];

// Skip validation if no rule defined
if (!rule) {
  return [{ json: { ...context, flags_ok: true, skip_reason: 'no_rule_for_action' } }];
}

// ─────────────────────────────────────────────────────────────────────────
// CHECK REQUIRED FLAGS
// ─────────────────────────────────────────────────────────────────────────
const stateFlags = project.state_flags || {};
const missingFlags = [];

for (const flag of rule.required_flags) {
  if (!stateFlags[flag]) {
    missingFlags.push({
      flag: flag,
      label: flag.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase()),
      responsible_agent: flag.includes('tracking') ? 'sora' : flag.includes('strategy') ? 'luna' : 'unknown',
      icon: flag.includes('tracking') ? 'activity' : 'target'
    });
  }
}

// ─────────────────────────────────────────────────────────────────────────
// CHECK REQUIRED PHASE
// ─────────────────────────────────────────────────────────────────────────
const currentPhase = project.current_phase;
const wrongPhase = rule.required_phase && !rule.required_phase.includes(currentPhase);

// ─────────────────────────────────────────────────────────────────────────
// IF VALIDATION FAILS → BLOCK & RETURN ERROR UI COMPONENT
// ─────────────────────────────────────────────────────────────────────────
if (missingFlags.length > 0 || wrongPhase) {
  throw new Error(JSON.stringify({
    flags_not_met: true,
    error_message: rule.message,
    ui_component: {
      type: 'ERROR_STATE',
      data: {
        error: rule.message,
        severity: 'blocking',
        validation_type: missingFlags.length > 0 ? 'missing_flags' : 'wrong_phase',
        missing_flags: missingFlags,
        current_phase: currentPhase,
        required_phases: rule.required_phase,
        resolution: missingFlags.length > 0 
          ? `Complete the following tasks first: ${missingFlags.map(f => f.label).join(', ')}`
          : `Project must be in ${rule.required_phase.join(' or ')} phase`
      }
    }
  }));
}

// ─────────────────────────────────────────────────────────────────────────
// FLAGS OK → CONTINUE
// ─────────────────────────────────────────────────────────────────────────
return [{ json: { ...context, flags_ok: true } }];

// ============================================================================
// PREPARE MILO CONTEXT - Format for AI Agent
// ============================================================================

const context = $input.first().json;

return [{
  json: {
    task_context: {
      project_id: context.project.id,
      project_name: context.project.name,
      project_scope: context.project.scope,
      project_phase: context.project.current_phase,
      task_id: context.task?.id || null,
      task_title: context.task?.title || "Creative Request",
      task_description: context.task?.description || "",
      user_inputs: context.task?.user_inputs || context.user_input
    },
    brand: context.brand_identity,
    strategy: context.strategy,
    project_memory: context.project_memory,
    creative_request: {
      message: context.user_input.message || context.user_input.chatInput || "Generate creative assets",
      action: context.user_input.action || 'generate_creatives',
      session_id: context.session_id,
      timestamp: context.timestamp
    },
    // Pass context for later
    full_context: context
  }
}];

