// ============================================================
// TOOL: nano_banana_pro (WRAPPED WITH COST TRACKING)
// ============================================================

const config = $input.json;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_ANON_KEY = $env.SUPABASE_ANON_KEY;
const GOOGLE_API_KEY = $env.GOOGLE_API_KEY;
const GOOGLE_PROJECT_ID = $env.GOOGLE_PROJECT_ID || 'the-hive-os-v4';

if (!config.prompt) {
  return { success: false, error: "prompt is required" };
}

const {
  prompt,
  resolution = "4096x4096",
  style = "professional_photo",
  quality = "professional",
  negative_prompt = "blurry, low quality, watermark, text, logo",
  creativity = 70
} = config;

const operation = 'generate_image';
const projectId = config.project_id || null;
const taskId = config.task_id || null;

try {
  // ─────────────────────────────────────────────────────────
  // 1. CHECK QUOTA BEFORE GENERATION
  // ─────────────────────────────────────────────────────────
  const quotaResponse = await fetch(`${SUPABASE_URL}/rest/v1/rpc/check_quota_before_operation`, {
    method: 'POST',
    headers: {
      'apikey': SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      p_operation: operation,
      p_credits_required: 10 // generate_image costs 10 credits
    })
  });

  if (!quotaResponse.ok) {
    const errorText = await quotaResponse.text();
    return {
      success: false,
      error: 'Failed to check quota',
      details: errorText
    };
  }

  const quotaData = await quotaResponse.json();
  const quotaCheck = Array.isArray(quotaData) ? quotaData[0] : quotaData;

  if (!quotaCheck.allowed) {
    return {
      success: false,
      quota_exceeded: true,
      error: quotaCheck.error_message,
      error_code: quotaCheck.error_code,
      credits_remaining: quotaCheck.credits_remaining,
      usage_percent: quotaCheck.usage_percent
    };
  }

  // ─────────────────────────────────────────────────────────
  // 2. GENERATE IMAGE (Google Imagen 3)
  // ─────────────────────────────────────────────────────────
  const startTime = Date.now();

  const imageResponse = await fetch(
    `https://us-central1-aiplatform.googleapis.com/v1/projects/${GOOGLE_PROJECT_ID}/locations/us-central1/publishers/google/models/imagegeneration@006:predict`,
    {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${GOOGLE_API_KEY}`
      },
      body: JSON.stringify({
        instances: [{ prompt: prompt, negativePrompt: negative_prompt }],
        parameters: {
          sampleCount: 1,
          aspectRatio: "1:1",
          safetySetting: "block_some",
          personGeneration: "allow_adult"
        }
      })
    }
  );

  const duration = Date.now() - startTime;

  if (!imageResponse.ok) {
    const errorData = await imageResponse.json();

    // Track failed generation
    await fetch(`${SUPABASE_URL}/rest/v1/rpc/record_api_usage`, {
      method: 'POST',
      headers: {
        'apikey': SUPABASE_ANON_KEY,
        'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        p_project_id: projectId,
        p_task_id: taskId,
        p_agent_id: 'milo',
        p_operation: operation,
        p_provider: 'nano-banana-pro',
        p_model: 'imagen-3-fast',
        p_credits_consumed: 10,
        p_cost_usd: 0.04,
        p_request_params: { prompt, resolution, style },
        p_response_metadata: { duration_ms: duration, error: errorData },
        p_status: 'failed',
        p_error_message: `API Error: ${imageResponse.status}`
      })
    });

    return {
      success: false,
      error: `Google API Error: ${imageResponse.status}`,
      details: errorData
    };
  }

  const imageData = await imageResponse.json();
  const imageBase64 = imageData.predictions[0].bytesBase64Encoded;

  // ─────────────────────────────────────────────────────────
  // 3. TRACK SUCCESSFUL GENERATION
  // ─────────────────────────────────────────────────────────
  await fetch(`${SUPABASE_URL}/rest/v1/rpc/record_api_usage`, {
    method: 'POST',
    headers: {
      'apikey': SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      p_project_id: projectId,
      p_task_id: taskId,
      p_agent_id: 'milo',
      p_operation: operation,
      p_provider: 'nano-banana-pro',
      p_model: 'imagen-3-fast',
      p_credits_consumed: 10,
      p_cost_usd: 0.04,
      p_request_params: { prompt, resolution, style, negative_prompt },
      p_response_metadata: { duration_ms: duration, resolution: resolution },
      p_status: 'success',
      p_error_message: null
    })
  });

  // ─────────────────────────────────────────────────────────
  // 4. RETURN SUCCESS
  // ─────────────────────────────────────────────────────────
  return {
    success: true,
    tool: "nano_banana_pro",
    model: "imagen-3",
    output: {
      image_base64: imageBase64,
      format: "png",
      resolution: resolution,
      style: style,
      quality: quality,
      prompt_used: prompt,
      negative_prompt_used: negative_prompt,
      metadata: {
        creativity: creativity,
        generated_at: new Date().toISOString(),
        duration_ms: duration,
        credits_consumed: 10,
        cost_usd: 0.04
      }
    },
    message: "Image 4K generated successfully (10 credits consumed)"
  };

} catch (error) {
  return {
    success: false,
    tool: "nano_banana_pro",
    error: error.message,
    details: error.toString()
  };
}

