      p_response_metadata: { duration_ms: durationMs, dimensions: dimensions, video_url: videoUrl },
      p_status: 'success',
      p_error_message: null
    })
  });

  // ─────────────────────────────────────────────────────────
  // 4. RETURN SUCCESS
  // ─────────────────────────────────────────────────────────
  return {
    success: true,
    tool: "veo3",
    model: "veo-3",
    output: {
      video_url: videoUrl,
      video_base64: videoBase64,
      format: "mp4",
      duration_seconds: duration,
      resolution: resolution,
      dimensions: dimensions,
      fps: fps,
      style: style,
      camera_motion: camera_motion,
