        duration_ms: durationMs,
        file_size_estimate_mb: Math.round(duration * 10),
        credits_consumed: 100,
        cost_usd: 0.12
      }
    },
    message: `Video ${duration}s generated successfully in ${resolution} (100 credits consumed)`
  };

} catch (error) {
  return {
    success: false,
    tool: "veo3",
    error: error.message,
    details: error.toString()
  };
}

