const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_ANON_KEY = $env.SUPABASE_ANON_KEY;
const ELEVENLABS_API_KEY = $env.ELEVENLABS_API_KEY;

if (!ELEVENLABS_API_KEY) {
  return { success: false, error: 'ELEVENLABS_API_KEY not configured in environment' };
}

const mode = config.mode || (config.text ? "tts" : "sound_effects");
const projectId = config.project_id || null;
const taskId = config.task_id || null;

// ─────────────────────────────────────────────────────────
// MODE: TEXT-TO-SPEECH
// ─────────────────────────────────────────────────────────
if (mode === "tts") {
  if (!config.text) {
    return { success: false, error: "text is required for TTS mode" };
  }

  const {
    text,
    voice_id = "21m00Tcm4TlvDq8ikWAM",
    model = "multilingual_v2",
    stability = 0.75,
    similarity_boost = 0.75,
    style = 0.5,
    use_speaker_boost = true,
    language_code = "en"
  } = config;

  const operation = 'text_to_speech';

