      body: JSON.stringify({
        p_operation: operation,
        p_credits_required: 5 // text_to_speech costs 5 credits
      })
    });

    if (!quotaResponse.ok) {
      const errorText = await quotaResponse.text();
      return {
        success: false,
        error: 'Failed to check quota',
        details: errorText
      };
    }

    const quotaData = await quotaResponse.json();
    const quotaCheck = Array.isArray(quotaData) ? quotaData[0] : quotaData;

    if (!quotaCheck.allowed) {
      return {
        success: false,
        quota_exceeded: true,
        error: quotaCheck.error_message,
        error_code: quotaCheck.error_code,
        credits_remaining: quotaCheck.credits_remaining,
        usage_percent: quotaCheck.usage_percent
      };
    }

    // ─────────────────────────────────────────────────────────
    // 2. GENERATE AUDIO (ElevenLabs TTS)
    // ─────────────────────────────────────────────────────────
    const startTime = Date.now();

    const audioResponse = await fetch(
      `https://api.elevenlabs.io/v1/text-to-speech/${voice_id}`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'xi-api-key': ELEVENLABS_API_KEY
        },
        body: JSON.stringify({
          text: text,
          model_id: model,
          voice_settings: {
            stability: stability,
            similarity_boost: similarity_boost,
            style: style,
            use_speaker_boost: use_speaker_boost
          }
        })
      }
    );

    const durationMs = Date.now() - startTime;

    if (!audioResponse.ok) {
      const errorData = await audioResponse.json();

      // Track failed generation
      await fetch(`${SUPABASE_URL}/rest/v1/rpc/record_api_usage`, {
        method: 'POST',
        headers: {
          'apikey': SUPABASE_ANON_KEY,
          'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          p_project_id: projectId,
          p_task_id: taskId,
          p_agent_id: 'milo',
          p_operation: operation,
          p_provider: 'elevenlabs',
          p_model: model,
          p_credits_consumed: 5,
          p_cost_usd: 0.03,
          p_request_params: { text, voice_id, model },
          p_response_metadata: { duration_ms: durationMs, error: errorData },
          p_status: 'failed',
          p_error_message: `API Error: ${audioResponse.status}`
        })
      });

      return {
        success: false,
        error: `ElevenLabs API Error: ${audioResponse.status}`,
        details: errorData
      };
    }

    const audioBuffer = await audioResponse.arrayBuffer();
    const audioBase64 = Buffer.from(audioBuffer).toString('base64');

    // ─────────────────────────────────────────────────────────
    // 3. TRACK SUCCESSFUL GENERATION
    // ─────────────────────────────────────────────────────────
    await fetch(`${SUPABASE_URL}/rest/v1/rpc/record_api_usage`, {
      method: 'POST',
      headers: {
        'apikey': SUPABASE_ANON_KEY,
        'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        p_project_id: projectId,
        p_task_id: taskId,
        p_agent_id: 'milo',
        p_operation: operation,
        p_provider: 'elevenlabs',
        p_model: model,
        p_credits_consumed: 5,
        p_cost_usd: 0.03,
        p_request_params: { text, voice_id, model, language_code },
        p_response_metadata: { duration_ms: durationMs, sample_rate: 44100 },
        p_status: 'success',
        p_error_message: null
      })
    });

    // ─────────────────────────────────────────────────────────
    // 4. RETURN SUCCESS
    // ─────────────────────────────────────────────────────────
    return {
      success: true,
      tool: "elevenlabs",
      mode: "tts",
      output: {
        audio_base64: audioBase64,
        format: "mp3",
        sample_rate: 44100,
        duration_estimate_seconds: Math.ceil(text.length / 15),
        text_used: text,
        voice_id: voice_id,
        model: model,
        language: language_code,
        metadata: {
          stability: stability,
          similarity_boost: similarity_boost,
          style: style,
          generated_at: new Date().toISOString(),
          duration_ms: durationMs,
          credits_consumed: 5,
          cost_usd: 0.03
        }
      },
      message: "Audio TTS generated successfully (5 credits consumed)"
    };

  } catch (error) {
    return {
      success: false,
      tool: "elevenlabs",
      mode: "tts",
      error: error.message,
      details: error.toString()
    };
  }

} else {
  // ─────────────────────────────────────────────────────────
  // MODE: SOUND EFFECTS
  // ─────────────────────────────────────────────────────────
  if (!config.prompt) {
    return { success: false, error: "prompt is required for sound_effects mode" };
  }

  const {
    prompt,
    duration_seconds = 5,
    prompt_influence = 0.5
  } = config;

  if (duration_seconds < 0.5 || duration_seconds > 22) {
    return { success: false, error: "duration_seconds must be between 0.5 and 22" };
  }

  const operation = 'sound_effects';

  try {
    // Same pattern: check quota → generate → track
    const quotaResponse = await fetch(`${SUPABASE_URL}/rest/v1/rpc/check_quota_before_operation`, {
      method: 'POST',
      headers: {
        'apikey': SUPABASE_ANON_KEY,
