        error: quotaCheck.error_message
      };
    }

    const startTime = Date.now();

    const sfxResponse = await fetch(
      'https://api.elevenlabs.io/v1/sound-generation',
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'xi-api-key': ELEVENLABS_API_KEY
        },
        body: JSON.stringify({
          text: prompt,
          duration_seconds: duration_seconds,
          prompt_influence: prompt_influence
        })
      }
    );

    const durationMs = Date.now() - startTime;

    if (!sfxResponse.ok) {
      const errorData = await sfxResponse.json();

      await fetch(`${SUPABASE_URL}/rest/v1/rpc/record_api_usage`, {
        method: 'POST',
        headers: {
          'apikey': SUPABASE_ANON_KEY,
          'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          p_project_id: projectId,
          p_task_id: taskId,
          p_agent_id: 'milo',
          p_operation: operation,
          p_provider: 'elevenlabs',
          p_model: 'sound-generation',
          p_credits_consumed: 5,
          p_cost_usd: 0.03,
          p_request_params: { prompt, duration_seconds },
          p_response_metadata: { duration_ms: durationMs, error: errorData },
          p_status: 'failed',
          p_error_message: `API Error: ${sfxResponse.status}`
        })
      });

      return {
        success: false,
        error: `ElevenLabs API Error: ${sfxResponse.status}`,
        details: errorData
      };
    }

    const audioBuffer = await sfxResponse.arrayBuffer();
    const audioBase64 = Buffer.from(audioBuffer).toString('base64');

    await fetch(`${SUPABASE_URL}/rest/v1/rpc/record_api_usage`, {
      method: 'POST',
      headers: {
        'apikey': SUPABASE_ANON_KEY,
        'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        p_project_id: projectId,
        p_task_id: taskId,
        p_agent_id: 'milo',
