        p_credits_consumed: 5,
        p_cost_usd: 0.03,
        p_request_params: { prompt, duration_seconds, prompt_influence },
        p_response_metadata: { duration_ms: durationMs },
        p_status: 'success',
        p_error_message: null
      })
    });

    return {
      success: true,
      tool: "elevenlabs",
      mode: "sound_effects",
      output: {
        audio_base64: audioBase64,
        format: "mp3",
        sample_rate: 44100,
