          duration_ms: durationMs,
          credits_consumed: 5,
          cost_usd: 0.03
        }
      },
      message: `Sound effect ${duration_seconds}s generated successfully (5 credits consumed)`
    };

  } catch (error) {
    return {
      success: false,
      tool: "elevenlabs",
      mode: "sound_effects",
